// LeagueGeneration.js actualizado con lógica de ascensos/descensos condicionales

import { crearClasificacion } from "./crearClasificacion";
import { generarJornadasLiga } from "./calendario";
import equiposOriginales from "../data/equipos.json";

function generarLigas() {
    const esPrimeraVez = JSON.parse(localStorage.getItem("esLigaPrimera")) ?? true;

    if (esPrimeraVez) {
        localStorage.setItem("esLigaPrimera", JSON.stringify(false));
        return generarLigasIniciales();
    } else {
        return reorganizarLigasConAscensosYDescensos();
    }
}

function generarLigasIniciales() {
    const ligas = {};
    const equipos = equiposOriginales;

    equipos.forEach(equipo => {
        if (!ligas[equipo.liga]) ligas[equipo.liga] = [];
        ligas[equipo.liga].push(equipo);
    });

    Object.keys(ligas).forEach(nombreLiga => {
        const clasificacion = crearClasificacion(ligas[nombreLiga]);
        const calendario = generarJornadasLiga(clasificacion);
        ligas[nombreLiga] = clasificacion;
        localStorage.setItem(`clasificacion_${nombreLiga}`, JSON.stringify(clasificacion));
        localStorage.setItem(`calendario_${nombreLiga}`, JSON.stringify(calendario));
    });

    localStorage.setItem("equipos", JSON.stringify(equipos));
    return ligas;
}

function reorganizarLigasConAscensosYDescensos() {
    const ligas = {};
    const ascensos = JSON.parse(localStorage.getItem("ascendidos_playoffs")) || {};
    const clasificaciones = {};
    const equipos = JSON.parse(localStorage.getItem("equipos")) || [];
    const ligasDisponibles = ["Liga 1", "Liga 2", "Primera RFEF - Grupo 1", "Primera RFEF - Grupo 2",
        "Segunda RFEF - Grupo 1", "Segunda RFEF - Grupo 2", "Segunda RFEF - Grupo 3", "Segunda RFEF - Grupo 4", "Segunda RFEF - Grupo 5",
        ...new Set(equipos.map(e => e.liga).filter(l => l.startsWith("Tercera RFEF")))
    ];

    // Obtener clasificaciones previas
    ligasDisponibles.forEach(liga => {
        const clas = JSON.parse(localStorage.getItem(`clasificacion_${liga}`)) || [];
        clasificaciones[liga] = clas;
    });

    // Descensos y ascensos
    const nuevosEquipos = [];

    // LIGA 1
    const liga1 = clasificaciones["Liga 1"];
    const descendidosL1 = liga1.slice(-3);
    const permanecenL1 = liga1.slice(0, -3);
    const ascendidosL2 = clasificaciones["Liga 2"].slice(0, 2).concat(ascensos["Liga 2"] || []);
    moverEquipos(permanecenL1, "Liga 1", nuevosEquipos);
    moverEquipos(ascendidosL2, "Liga 1", nuevosEquipos);

    // LIGA 2
    const liga2 = clasificaciones["Liga 2"];
    const descendidosL2 = liga2.slice(-4);
    const restantesL2 = liga2.slice(2, -4); // Quitando 2 ascendidos y 4 descendidos
    const ascendidosPREF = clasificaciones["Primera RFEF - Grupo 1"].slice(0, 1)
        .concat(clasificaciones["Primera RFEF - Grupo 2"].slice(0, 1))
        .concat(ascensos["Primera RFEF"] || []);
    moverEquipos(restantesL2, "Liga 2", nuevosEquipos);
    moverEquipos(descendidosL1, "Liga 2", nuevosEquipos);
    moverEquipos(ascendidosPREF, "Liga 2", nuevosEquipos);

    // PRIMERA RFEF
    const descendidosPREF = [];
    const permanecenPREF = [];
    for (let g = 1; g <= 2; g++) {
        const grupo = clasificaciones[`Primera RFEF - Grupo ${g}`];
        descendidosPREF.push(...grupo.slice(-10));
        permanecenPREF.push(...grupo.slice(1, -10)); // quitamos líder (asciende)
    }
    const ascendidosSREF = [];
    for (let g = 1; g <= 5; g++) {
        const lider = clasificaciones[`Segunda RFEF - Grupo ${g}`]?.[0];
        if (lider) ascendidosSREF.push(lider);
    }
    ascendidosSREF.push(...(ascensos["Segunda RFEF"] || []));
    moverEquipos(permanecenPREF, null, nuevosEquipos);
    moverEquipos(descendidosL2, null, nuevosEquipos, true); // los que bajan
    moverEquipos(ascendidosSREF, null, nuevosEquipos);

    // SEGUNDA RFEF
    const descendidosSREF = [];
    const permanecenSREF = [];
    for (let g = 1; g <= 5; g++) {
        const grupo = clasificaciones[`Segunda RFEF - Grupo ${g}`];
        descendidosSREF.push(...grupo.slice(-5));
        permanecenSREF.push(...grupo.slice(1, -5)); // excluye líder y últimos 5
    }
    moverEquipos(permanecenSREF, null, nuevosEquipos);
    moverEquipos(descendidosPREF, null, nuevosEquipos);
    moverEquipos(ascensos["Tercera RFEF"] || [], null, nuevosEquipos);

    // TERCERA RFEF
    const terceros = equipos.filter(e => e.liga.startsWith("Tercera RFEF"));
    const regionales = equipos.filter(e => e.liga.startsWith("Regionales"));
    moverEquipos(descendidosSREF, null, nuevosEquipos);
    moverEquipos(terceros.filter(e => !nuevosEquipos.includes(e)), null, nuevosEquipos);
    moverEquipos(regionales.slice(0, 20), null, nuevosEquipos); // relleno por si faltan

    // Reasignar ligas
    asignarNuevaLiga(nuevosEquipos);

    // Guardar y generar nuevas jornadas y clasificaciones
    const ligasFinales = {};
    nuevosEquipos.forEach(e => {
        if (!ligasFinales[e.liga]) ligasFinales[e.liga] = [];
        ligasFinales[e.liga].push(e);
    });

    Object.entries(ligasFinales).forEach(([liga, eqs]) => {
        const clasificacion = crearClasificacion(eqs);
        const calendario = generarJornadasLiga(clasificacion);
        localStorage.setItem(`clasificacion_${liga}`, JSON.stringify(clasificacion));
        localStorage.setItem(`calendario_${liga}`, JSON.stringify(calendario));
    });

    localStorage.setItem("equipos", JSON.stringify(nuevosEquipos));
    return ligasFinales;
}

// Ayuda: mover equipos y actualizar liga
function moverEquipos(lista, nuevaLiga, destino, mantenerLiga = false) {
    lista.forEach(e => {
        const copia = { ...e };
        if (!mantenerLiga) copia.liga = nuevaLiga || copia.liga;
        destino.push(copia);
    });
}

// Asignación geográfica (muy simplificada)
function asignarNuevaLiga(equipos) {
    // Implementa tu lógica real de reparto geográfico aquí
    equipos.forEach(e => {
        if (e.liga.startsWith("Liga") || e.liga.startsWith("Primera")) return;
        if (["Galicia", "Asturias", "Cantabria"].includes(e.comunidad)) e.liga = "Segunda RFEF - Grupo 1";
        else if (["País Vasco", "Navarra", "La Rioja"].includes(e.comunidad)) e.liga = "Segunda RFEF - Grupo 2";
        else if (["Cataluña", "Valencia", "Aragón", "Baleares"].includes(e.comunidad)) e.liga = "Segunda RFEF - Grupo 3";
        else if (["Andalucía", "Extremadura", "Murcia"].includes(e.comunidad)) e.liga = "Segunda RFEF - Grupo 4";
        else if (["Madrid", "Castilla-La Mancha", "Canarias"].includes(e.comunidad)) e.liga = "Segunda RFEF - Grupo 5";
        else if (e.liga.startsWith("Tercera") || e.liga.startsWith("Regionales")) {
            e.liga = `Tercera RFEF - ${e.comunidad}`;
        }
    });
}

export default generarLigas;
